+fn max_redaction_level(
+    left: RecorderRedactionLevel,
+    right: RecorderRedactionLevel,
+) -> RecorderRedactionLevel {
+    use RecorderRedactionLevel::{Full, None, Partial};
+    match (left, right) {
+        (Full, _) | (_, Full) => Full,
+        (Partial, _) | (_, Partial) => Partial,
+        (None, None) => None,
+    }
